package com.hospital.management.controller.appointment;import com.hospital.management.service.*;import com.hospital.management.service.impl.AppointmentServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.Set;
@WebServlet("/appointments/status")public class AppointmentStatusServlet extends HttpServlet {private final AppointmentService service;public AppointmentStatusServlet(){this(new AppointmentServiceImpl());}public AppointmentStatusServlet(AppointmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=AppointmentRequest.id(q.getParameter("appointmentId"));String action=q.getParameter("action");if(id==null||!Set.of("confirm","complete","cancel","no_show").contains(action)){r.sendError(400);return;}ServiceResult<Void>x=service.updateAppointmentStatus(id,action,AppointmentRequest.audit(q),AppointmentRequest.user(q));r.sendRedirect(q.getContextPath()+"/appointments/view?id="+id+"&"+(x.isSuccess()?"message=updated":"error=status"));}}
